import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { Eye } from 'lucide-react';
import { DataTable } from '../../components/ui/DataTable';
import { PageHeader } from '../../components/common/PageHeader';
import { Button } from '../../components/common/Button';
import { getApplicants, updateApplicantOCR } from '../../services/applicant.service';
import { getDistricts } from '../../services/master.service';
import toast from 'react-hot-toast';
import { formatDateIST } from '../../utils/date';

const ApplicantList = () => {
    const navigate = useNavigate();
    const [applicants, setApplicants] = useState([]);
    const [loading, setLoading] = useState(true);
    const [searchQuery, setSearchQuery] = useState('');
    const [page, setPage] = useState(1);
    const [limit, setLimit] = useState(10);
    const [totalPages, setTotalPages] = useState(1);
    const [totalItems, setTotalItems] = useState(0);
    const [selectedApplicants, setSelectedApplicants] = useState([]);
    const [ocrUpdating, setOcrUpdating] = useState(false);

    const [districts, setDistricts] = useState([]);
    const [selectedDistrict, setSelectedDistrict] = useState('');

    useEffect(() => {
        const loadDistricts = async () => {
            try {
                const res = await getDistricts({ is_active: true });
                setDistricts(Array.isArray(res) ? res : res.districts || []);
            } catch (err) {
                console.error('Failed to load districts', err);
            }
        };
        loadDistricts();
    }, []);

    const fetchApplicants = useCallback(async () => {
        setLoading(true);
        try {
            const params = {
                page,
                limit,
                search: searchQuery,
                district_id: selectedDistrict || undefined
            };
            const response = await getApplicants(params);
            const applicantsData = response?.data?.data?.applicants || response?.applicants || [];
            const pagination = response?.data?.pagination || response?.pagination || {};
            setApplicants(applicantsData);
            setTotalPages(pagination.totalPages || 1);
            setTotalItems(pagination.total ?? pagination.totalItems ?? 0);
        } catch (err) {
            console.error('Failed to fetch applicants', err);
            toast.error(err.message || 'Failed to load applicants');
        } finally {
            setLoading(false);
        }
    }, [page, limit, searchQuery, selectedDistrict]);

    useEffect(() => {
        fetchApplicants();
    }, [fetchApplicants]);

    const handleBulkOCRUpdate = async (ocrDisabled) => {
        if (selectedApplicants.length === 0) {
            toast.error('Please select at least one applicant');
            return;
        }
        setOcrUpdating(true);
        try {
            const ids = selectedApplicants.map(a => a.applicant_id || a.user_id);
            await updateApplicantOCR(ids, ocrDisabled);
            setApplicants(prev => prev.map(a => {
                const id = a.applicant_id || a.user_id;
                if (ids.includes(id)) {
                    return { ...a, ocr_disabled: ocrDisabled };
                }
                return a;
            }));
            toast.success(`OCR ${ocrDisabled ? 'disabled' : 'enabled'} for ${ids.length} applicant(s)`);
            setSelectedApplicants([]);
        } catch (err) {
            console.error('Failed to update OCR', err);
            toast.error(err.message || 'Failed to update OCR');
        } finally {
            setOcrUpdating(false);
        }
    };

    const columns = useMemo(() => [
        {
            key: 'applicant_no',
            header: 'Applicant No',
            sortable: true
        },
        {
            key: 'full_name',
            header: 'Name',
            sortable: true,
            render: (_, row = {}) => {
                const age = row.dob ? new Date().getFullYear() - new Date(row.dob).getFullYear() : null;
                const completion = Number.isFinite(row.profile_completion)
                    ? Math.min(100, Math.max(0, Math.round(row.profile_completion)))
                    : null;
                return (
                    <div>
                        <div className="font-medium text-slate-900">{row.full_name}</div>
                        <div className="text-xs text-slate-500 capitalize">
                            {row.gender ? `${row.gender}` : ''}{age && row.gender ? ' • ' : ''}{age ? `${age} years` : ''}
                        </div>
                        {completion !== null && (
                            <div className="mt-1.5 flex items-center gap-2">
                                <div className="h-1.5 w-24 bg-slate-200 rounded-full overflow-hidden">
                                    <div
                                        className="h-full bg-blue-500 rounded-full"
                                        style={{ width: `${completion}%` }}
                                    />
                                </div>
                                <span className="text-xs text-slate-500">{completion}%</span>
                            </div>
                        )}
                    </div>
                );
            }
        },
        {
            key: 'contact',
            header: 'Contact',
            render: (_, row = {}) => (
                <div>
                    <div className="text-sm font-medium text-slate-700">{row.mobile_no}</div>
                    <div className="text-xs text-slate-400">{row.email}</div>
                </div>
            )
        },
        {
            key: 'application_count',
            header: 'Applications',
            className: 'text-center',
            render: (_, row = {}) => (
                <span className="inline-flex items-center justify-center w-7 h-7 rounded-lg bg-blue-50 text-blue-700 text-xs font-bold border border-blue-100">
                    {row.application_count || 0}
                </span>
            )
        },
        {
            key: 'ocr_disabled',
            header: 'OCR',
            className: 'text-center',
            render: (_, row = {}) => (
                <span className={`inline-flex items-center gap-1 px-2.5 py-1 rounded-full text-xs font-semibold border ${
                    row.ocr_disabled
                        ? 'bg-red-50 text-red-600 border-red-200'
                        : 'bg-emerald-50 text-emerald-700 border-emerald-200'
                }`}>
                    <span className={`w-1.5 h-1.5 rounded-full ${row.ocr_disabled ? 'bg-red-400' : 'bg-emerald-500'}`} />
                    {row.ocr_disabled ? 'Disabled' : 'Enabled'}
                </span>
            )
        },
        {
            key: 'registration_date',
            header: 'Registered On',
            sortable: true,
            render: (_, row = {}) => (
                <span className="text-sm text-slate-500">
                    {formatDateIST(row.created_at, { includeTime: false })}
                </span>
            )
        },
        {
            key: 'actions',
            header: 'Actions',
            className: 'text-center',
            render: (_value, row = {}) => (
                <div className="flex justify-center">
                    <Button
                        variant="ghost"
                        size="sm"
                        onClick={() => navigate(`/applicants/${row.applicant_id || row.user_id}`)}
                        title="View"
                        className="w-8 h-8 p-0 rounded-lg bg-slate-100 text-slate-500 hover:bg-blue-50 hover:text-blue-600 hover:border-blue-200 border border-transparent active:scale-95 transition-all duration-150 shadow-sm"
                    >
                        <Eye className="h-3.5 w-3.5" />
                    </Button>
                </div>
            ),
        },
    ], [navigate]);

    return (
        <div className="space-y-6">
            <PageHeader
                title="Applicants"
                description="View and manage registered applicants"
                extraActions={
                    <div className="flex items-center gap-2">
                        {selectedApplicants.length > 0 && (
                            <span className="text-xs font-semibold text-slate-500 bg-slate-100 px-2.5 py-1 rounded-lg">
                                {selectedApplicants.length} selected
                            </span>
                        )}
                        <Button
                            variant="secondary"
                            size="sm"
                            onClick={() => handleBulkOCRUpdate(false)}
                            disabled={ocrUpdating || selectedApplicants.length === 0}
                            className="text-xs font-semibold rounded-xl px-3 py-2 border border-emerald-200 bg-emerald-50 text-emerald-700 hover:bg-emerald-100 disabled:opacity-40 disabled:cursor-not-allowed transition-all"
                        >
                            Enable OCR
                        </Button>
                        <Button
                            variant="secondary"
                            size="sm"
                            onClick={() => handleBulkOCRUpdate(true)}
                            disabled={ocrUpdating || selectedApplicants.length === 0}
                            className="text-xs font-semibold rounded-xl px-3 py-2 border border-red-200 bg-red-50 text-red-600 hover:bg-red-100 disabled:opacity-40 disabled:cursor-not-allowed transition-all"
                        >
                            Disable OCR
                        </Button>

                    </div>
                }
            />

            <DataTable
                columns={columns}
                data={applicants}
                onSearch={setSearchQuery}
                onSelectionChange={setSelectedApplicants}
                selectionResetKey={page}
                pagination={{
                    currentPage: page,
                    totalPages: totalPages,
                    totalItems,
                    onPageChange: setPage,
                    pageSize: limit,
                    onPageSizeChange: (l) => { setLimit(l); setPage(1); },
                    pageSizeOptions: [10, 25, 50, 100]
                }}
                isLoading={loading}
                rowKey="applicant_id"
                headerClassName="bg-slate-900 text-white"
                showRowNumbers={true}
            />
        </div>
    );
};

export default ApplicantList;